func TestStoreCreate_RejectsCanceledContext(t *testing.T) {
	t.Parallel()
	store := newTestStore(t)
	ctx, cancel := context.WithCancel(context.Background())
	cancel()

	b := &Bead{Title: "canceled create", IssueType: DefaultType, Priority: 2}
	err := store.Create(ctx, b)
	require.Error(t, err)
	require.ErrorIs(t, err, context.Canceled)
	assert.Empty(t, b.ID, "canceled create must not assign an ID")
}

func TestStoreUpdate_RejectsCanceledContext(t *testing.T) {
	t.Parallel()
	store := newTestStore(t)
	b := &Bead{Title: "original", IssueType: DefaultType, Priority: 2}
	require.NoError(t, store.Create(context.Background(), b))

	ctx, cancel := context.WithCancel(context.Background())
	cancel()

	err := store.Update(ctx, b.ID, func(updated *Bead) {
		updated.Title = "mutated"
	})
	require.Error(t, err)
	require.ErrorIs(t, err, context.Canceled)

	got, err := store.Get(context.Background(), b.ID)
	require.NoError(t, err)
	assert.Equal(t, "original", got.Title)
}

func TestStoreClose_RejectsCanceledContext(t *testing.T) {
	t.Parallel()
	store := newTestStore(t)
	b := &Bead{Title: "close me", IssueType: DefaultType, Priority: 2}
	require.NoError(t, store.Create(context.Background(), b))

	ctx, cancel := context.WithCancel(context.Background())
	cancel()

	err := store.Close(ctx, b.ID)
	require.Error(t, err)
	require.ErrorIs(t, err, context.Canceled)

	got, err := store.Get(context.Background(), b.ID)
	require.NoError(t, err)
	assert.Equal(t, StatusOpen, got.Status)
}

